Expr*
Ast2Asg::operator()(ast::ExpressionContext* ctx)
{
  auto list = ctx->assignmentExpression();
  Expr* ret = self(list[0]);

  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kComma;
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }

  return ret;
}

Expr*
Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->conditionalExpression())
    return self(p);

  auto ret = make<BinaryExpr>();
  ret->op = ret->kAssign;
  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}
// Generic binary expression helper
static BinaryExpr::Op tokenToBinaryOp(size_t tokenType)
{
  switch (tokenType) {
    case ast::Plus: return BinaryExpr::kAdd;
    case ast::Minus: return BinaryExpr::kSub;
    case ast::Star: return BinaryExpr::kMul;
    case ast::Slash: return BinaryExpr::kDiv;
    case ast::Percent: return BinaryExpr::kMod;
    case ast::Less: return BinaryExpr::kLt;
    case ast::Greater: return BinaryExpr::kGt;
    case ast::LessEqual: return BinaryExpr::kLe;
    case ast::GreaterEqual: return BinaryExpr::kGe;
    case ast::EqualEqual: return BinaryExpr::kEq;
    case ast::NotEqual: return BinaryExpr::kNe;
    case ast::AndAnd: return BinaryExpr::kAnd;
    case ast::OrOr: return BinaryExpr::kOr;
    case ast::And: return BinaryExpr::kINVALID; // Bitwise AND
    case ast::Or: return BinaryExpr::kINVALID;  // Bitwise OR
    case ast::Xor: return BinaryExpr::kINVALID; // Bitwise XOR
    default: ABORT();
  }
}

